-- name: seed_21th_step4_items_p4_p5
DO $$
DECLARE
  v_round_id uuid;
  v_part_p1 uuid; v_part_p2 uuid; v_part_p3 uuid;
  v_part_p4 uuid; v_part_p5 uuid;
BEGIN
  SELECT id INTO v_round_id FROM public.hrd_survey_rounds WHERE round_number = 21;
  IF v_round_id IS NULL THEN RAISE EXCEPTION 'round 21 not found'; END IF;
  SELECT id INTO v_part_p1 FROM public.hrd_survey_parts WHERE round_id=v_round_id AND part_code='p1';
  SELECT id INTO v_part_p2 FROM public.hrd_survey_parts WHERE round_id=v_round_id AND part_code='p2';
  SELECT id INTO v_part_p3 FROM public.hrd_survey_parts WHERE round_id=v_round_id AND part_code='p3';
  SELECT id INTO v_part_p4 FROM public.hrd_survey_parts WHERE round_id=v_round_id AND part_code='p4';
  SELECT id INTO v_part_p5 FROM public.hrd_survey_parts WHERE round_id=v_round_id AND part_code='p5';
END $$;
